USE OpenFinancialExchange;
GO

SET NOCOUNT ON;

-- =============================================================================
-- RESET: desativa IDENTITY_INSERT de qualquer execução anterior incompleta
-- (SQL Server só permite IDENTITY_INSERT ON em uma tabela por vez)
-- =============================================================================
BEGIN TRY SET IDENTITY_INSERT OfxBalances      OFF; END TRY BEGIN CATCH END CATCH;
BEGIN TRY SET IDENTITY_INSERT OfxTransactions  OFF; END TRY BEGIN CATCH END CATCH;
BEGIN TRY SET IDENTITY_INSERT OfxStatements    OFF; END TRY BEGIN CATCH END CATCH;
BEGIN TRY SET IDENTITY_INSERT OfxImports       OFF; END TRY BEGIN CATCH END CATCH;
BEGIN TRY SET IDENTITY_INSERT BankAccounts     OFF; END TRY BEGIN CATCH END CATCH;
BEGIN TRY SET IDENTITY_INSERT FinancialInstitutions OFF; END TRY BEGIN CATCH END CATCH;
GO

-- =============================================================================
-- LIMPEZA: remove dados existentes na ordem inversa das FKs
-- =============================================================================
DELETE FROM OfxBalances;
DELETE FROM OfxTransactions;
DELETE FROM OfxStatements;
DELETE FROM OfxImports;
DELETE FROM BankAccounts;
DELETE FROM FinancialInstitutions;

-- Reinicia os contadores IDENTITY para garantir consistência com os IDs do script
DBCC CHECKIDENT ('OfxBalances',      RESEED, 0);
DBCC CHECKIDENT ('OfxTransactions',  RESEED, 0);
DBCC CHECKIDENT ('OfxStatements',    RESEED, 0);
DBCC CHECKIDENT ('OfxImports',       RESEED, 0);
DBCC CHECKIDENT ('BankAccounts',     RESEED, 0);
DBCC CHECKIDENT ('FinancialInstitutions', RESEED, 0);
GO



